namespace sv_f7b4817aa23246dc9e95f019296f776e.Client.Models;

public class Shipment
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using sv_f7b4817aa23246dc9e95f019296f776e.Client.Models;

namespace sv_f7b4817aa23246dc9e95f019296f776e.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_f7b4817aa23246dc9e95f019296f776e.Client.Models;

namespace sv_f7b4817aa23246dc9e95f019296f776e.Client.Services;

public class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_f7b4817aa23246dc9e95f019296f776e.Client.Models;
using sv_f7b4817aa23246dc9e95f019296f776e.Client.Services;

namespace sv_f7b4817aa23246dc9e95f019296f776e.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Shipments = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment
        {
            TrackingNumber = "TRK-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 6, 2, 17, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 25, 9, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = new DateTime(2026, 5, 25, 14, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 26, 6, 15, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit to destination", Location = "Chicago, IL", Timestamp = new DateTime(2026, 5, 27, 8, 0, 0, DateTimeKind.Utc) }
            ]
        },
        ["TRK-002"] = new Shipment
        {
            TrackingNumber = "TRK-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 27, 12, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = new DateTime(2026, 5, 23, 10, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = new DateTime(2026, 5, 24, 16, 45, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 26, 7, 30, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = new DateTime(2026, 5, 26, 14, 20, 0, DateTimeKind.Utc) }
            ]
        },
        ["TRK-003"] = new Shipment
        {
            TrackingNumber = "TRK-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = new DateTime(2026, 6, 5, 18, 0, 0, DateTimeKind.Utc),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Order received", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 27, 20, 0, 0, DateTimeKind.Utc) },
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = new DateTime(2026, 5, 27, 20, 5, 0, DateTimeKind.Utc) }
            ]
        }
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        Shipments.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_f7b4817aa23246dc9e95f019296f776e.Client.Models
@using sv_f7b4817aa23246dc9e95f019296f776e.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment details for @TrackingNumber…</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger mt-2" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <h3>Shipment @_shipment.TrackingNumber</h3>

    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>

        <dt>Current Location</dt>
        <dd>@_shipment.Location</dd>

        @if (_shipment.EstimatedDelivery.HasValue)
        {
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
        }
    </dl>

    @if (_shipment.StatusUpdates.Count > 0)
    {
        <h4>Tracking History</h4>
        <table class="table">
            <thead>
                <tr>
                    <th>Time</th>
                    <th>Location</th>
                    <th>Description</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
                {
                    <tr>
                        <td>@update.Timestamp.ToString("g")</td>
                        <td>@update.Location</td>
                        <td>@update.Description</td>
                    </tr>
                }
            </tbody>
        </table>
    }
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        await CancelPendingRequestAsync();

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation away or disposal — silently stop
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong while loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    private async Task CancelPendingRequestAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = null;
    }
}

